<?php
namespace Tests\Feature\Hr;
use Illuminate\Support\Facades\Artisan; use Illuminate\Support\Facades\Schema; use Tests\TestCase;
class HrPhase3AMigrationsRollbackTest extends TestCase { use RefreshHrDatabase; public function test_payroll_prep_tables_exist():void{$this->assertTrue(Schema::hasColumns('hr_payroll_rules',['legal_entity_id','code','version','configuration','effective_from']));$this->assertTrue(Schema::hasColumns('hr_payroll_periods',['timesheet_period_id','status','source_hash','approved_at']));$this->assertTrue(Schema::hasColumns('hr_payroll_records',['employee_id','worked_minutes','approved_overtime_minutes','source_snapshot','source_hash']));} public function test_rollback_preserves_timesheets():void{Artisan::call('migrate:rollback',['--step'=>4]);Artisan::call('migrate:rollback',['--step'=>5]);Artisan::call('migrate:rollback',['--step'=>3]);Artisan::call('migrate:rollback',['--step'=>5]);Artisan::call('migrate:rollback',['--step'=>6]);Artisan::call('migrate:rollback',['--step'=>2]);Artisan::call('migrate:rollback',['--step'=>4]);Artisan::call('migrate:rollback',['--step'=>2]);Artisan::call('migrate:rollback',['--step'=>3]);Artisan::call('migrate:rollback',['--step'=>3]);$this->assertFalse(Schema::hasTable('hr_payroll_periods'));$this->assertTrue(Schema::hasTable('hr_timesheets'));$this->assertTrue(Schema::hasTable('hr_overtime_requests'));} }
